import { MessageEvent } from '@nitrots/nitro-renderer';

import { BlackjackModuleParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/BlackJackModuleParser';
export class BlackjackModuleEvent extends MessageEvent {
    constructor(callBack: Function) {
        super(callBack, BlackjackModuleParser);
    }

    public getParser(): BlackjackModuleParser {
        return this.parser as BlackjackModuleParser;
    }
}
